import numpy as np


def tansig(x):
    return 2 / (1 + np.exp(-2 * x)) - 1


def mapminmax_apply(x, settings):
    return (x - settings["xoffset"][:, np.newaxis]) * settings["gain"][
        :, np.newaxis
    ] + settings["ymin"]


def mapminmax_reverse(y, settings):
    return (y - settings["ymin"]) / settings["gain"] + settings["xoffset"]

